const JUZ_START_PAGE = [1, 22, 42, 63, 82, 102, 122, 142, 162, 182, 202, 222, 242, 262, 282, 302, 322, 342, 362, 382, 402, 422, 442, 462, 482, 503, 522, 542, 562, 582];
const TOTAL_PAGES = 604;

function pageOfAyat(surahNo, ayat) {
  const row = PAGE_MAP[surahNo - 1];
  if (!row) return null;
  const p = row[ayat - 1];
  return p || null;
}
function juzOfPage(page) {
  for (let j = JUZ_START_PAGE.length; j >= 1; j--) {
    if (page >= JUZ_START_PAGE[j - 1]) return j;
  }
  return 1;
}
function pagesInJuz(juz) {
  const start = JUZ_START_PAGE[juz - 1];
  const end = juz < 30 ? JUZ_START_PAGE[juz] - 1 : TOTAL_PAGES;
  return end - start + 1;
}
function maxAyatOf(suratName) {
  const s = SURAH.find((x) => x.name === suratName);
  return s ? s.ayat : 999;
}

