/* ---------------------------------------------------------------------- */
/* Util tanggal & jadwal (pekan selalu Senin-Minggu)                        */
/* ---------------------------------------------------------------------- */

function toDate(s) { return new Date(s + "T00:00:00"); }
function dayName(dateStr) { if (!dateStr) return ""; return HARI[toDate(dateStr).getDay()]; }
function fmtDate(dateStr) {
  if (!dateStr) return "";
  return toDate(dateStr).toLocaleDateString("id-ID", { day: "2-digit", month: "long", year: "numeric" });
}
/* Selalu kembalikan hari Senin dari pekan yang memuat dateStr, apapun hari aslinya */
function mondayOf(dateStr) {
  const d = toDate(dateStr);
  const isoDow = d.getDay() === 0 ? 7 : d.getDay(); // Senin=1 ... Minggu=7
  d.setDate(d.getDate() - (isoDow - 1));
  return d.toISOString().slice(0, 10);
}
function weekIndexOf(dateStr, refDateStr) {
  const a = toDate(mondayOf(dateStr));
  const b = toDate(mondayOf(refDateStr));
  const diffDays = Math.round((a - b) / 86400000);
  return Math.round(diffDays / 7);
}
function isoWeekKey(dateStr) { return mondayOf(dateStr); }
function getActivityMode(besar, tanggal, config) {
  const wi = weekIndexOf(tanggal, config.refDate);
  const parity = ((wi % 2) + 2) % 2 === 0;
  let mandiriBesar = parity ? "A" : "B";
  if (config.invert) mandiriBesar = mandiriBesar === "A" ? "B" : "A";
  return besar === mandiriBesar ? "mandiri" : "jamai";
}

/* ---------------------------------------------------------------------- */
/* Perhitungan progress hafalan (dari setoran ziyadah saja)                 */
/* ---------------------------------------------------------------------- */

function touchedPagesFromBaseline(perJuz) {
  const set = new Set();
  if (!perJuz) return set;
  Object.entries(perJuz).forEach(([juzStr, halaman]) => {
    const juz = Number(juzStr);
    const start = JUZ_START_PAGE[juz - 1];
    for (let i = 0; i < Number(halaman || 0); i++) set.add(start + i);
  });
  return set;
}
function touchedPagesFromEntries(entriesForNama) {
  const set = new Set();
  entriesForNama.forEach((e) => {
    if (!e.hadir) return;
    (e.setoran || []).forEach((row) => {
      if (row.jenis !== "ziyadah") return;
      const surahNo = SURAH_NO_BY_NAME[row.surat];
      if (!surahNo) return;
      const pFrom = pageOfAyat(surahNo, Number(row.ayatDari));
      const pTo = pageOfAyat(surahNo, Number(row.ayatSampai));
      if (!pFrom || !pTo) return;
      const lo = Math.min(pFrom, pTo), hi = Math.max(pFrom, pTo);
      for (let p = lo; p <= hi; p++) set.add(p);
    });
  });
  return set;
}
function computeHafalan(nama, entries, baselineRow) {
  const mine = entries.filter((e) => e.nama.trim().toLowerCase() === nama.trim().toLowerCase());
  const pagesBaseline = touchedPagesFromBaseline(baselineRow);
  const pagesEntries = touchedPagesFromEntries(mine);
  const allPages = new Set([...pagesBaseline, ...pagesEntries]);

  let completedJuz = 0, partialPages = 0;
  const perJuzDetail = [];
  for (let j = 1; j <= 30; j++) {
    const total = pagesInJuz(j);
    const start = JUZ_START_PAGE[j - 1];
    let touched = 0;
    for (let p = start; p < start + total; p++) if (allPages.has(p)) touched++;
    const done = touched === total;
    if (done) completedJuz++; else partialPages += touched;
    perJuzDetail.push({ juz: j, touched, total, done });
  }

  const ziyadahEntries = mine
    .filter((e) => e.hadir && (e.aktivitas || []).includes("ziyadah") && (e.setoran || []).some((r) => r.jenis === "ziyadah"))
    .sort((a, b) => (a.tanggal < b.tanggal ? 1 : a.tanggal > b.tanggal ? -1 : (a.createdAt < b.createdAt ? 1 : -1)));
  const last = ziyadahEntries[0] || null;
  const lastRows = last ? last.setoran.filter((r) => r.jenis === "ziyadah") : [];

  return {
    totalPagesTouched: allPages.size,
    completedJuz,
    partialPages,
    perJuzDetail,
    lastZiyadah: last ? { tanggal: last.tanggal, rows: lastRows } : null,
  };
}

